using DashboardCharts.Domain;using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Design;using Microsoft.EntityFrameworkCore.Metadata.Builders;using Microsoft.Extensions.Configuration;
namespace DashboardCharts.Persistence;/** <summary>Dashboard context.</summary> */ public sealed class DashboardChartsDbContext(DbContextOptions<DashboardChartsDbContext> o):DbContext(o){/** <summary>Schema.</summary> */ public const string Schema="dashboard";/** <summary>Definitions.</summary> */ public DbSet<ChartDefinition> Charts=>Set<ChartDefinition>();/** <inheritdoc/> */ protected override void OnModelCreating(ModelBuilder b){b.HasDefaultSchema(Schema);b.ApplyConfigurationsFromAssembly(typeof(DashboardChartsDbContext).Assembly);}}
/** <summary>Chart mapping.</summary> */ public sealed class ChartDefinitionConfiguration:IEntityTypeConfiguration<ChartDefinition>{/** <inheritdoc/> */ public void Configure(EntityTypeBuilder<ChartDefinition>b){b.ToTable("chart_definitions");b.HasKey(x=>x.Id);b.Property(x=>x.Title).HasMaxLength(200).IsRequired();b.Property(x=>x.Type).HasConversion<string>();b.Property(x=>x.DatasourceKey).HasMaxLength(100);b.Property(x=>x.XField).HasMaxLength(100);b.Property(x=>x.YField).HasMaxLength(100);b.Property(x=>x.Aggregation).HasConversion<string>();b.Property(x=>x.ColorsJson).HasColumnType("jsonb");b.Property(x=>x.FiltersJson).HasColumnType("jsonb");b.HasIndex(x=>x.LayoutOrder);}}
/** <summary>Repository.</summary> */ public sealed class ChartDefinitionRepository(DashboardChartsDbContext db):IChartDefinitionRepository{/** <inheritdoc/> */ public Task<ChartDefinition?>GetAsync(Guid id,CancellationToken ct)=>db.Charts.SingleOrDefaultAsync(x=>x.Id==id,ct);/** <inheritdoc/> */ public async Task<IReadOnlyList<ChartDefinition>>ListAsync(CancellationToken ct)=>await db.Charts.AsNoTracking().OrderBy(x=>x.LayoutOrder).ToListAsync(ct);/** <inheritdoc/> */ public void Add(ChartDefinition d)=>db.Charts.Add(d);/** <inheritdoc/> */ public void Remove(ChartDefinition d)=>db.Charts.Remove(d);/** <inheritdoc/> */ public async Task SaveAsync(CancellationToken ct)=>await db.SaveChangesAsync(ct);}
/** <summary>Tooling factory.</summary> */ public sealed class DashboardChartsDbContextFactory:IDesignTimeDbContextFactory<DashboardChartsDbContext>{/** <inheritdoc/> */ public DashboardChartsDbContext CreateDbContext(string[] args){var c=new ConfigurationBuilder().SetBasePath(Directory.GetCurrentDirectory()).AddJsonFile("appsettings.json",true).AddEnvironmentVariables().Build();var s=c.GetConnectionString("DashboardCharts")??c.GetConnectionString("Default")??"Host=localhost;Database=alfaris;Username=postgres;Password=postgres";return new(new DbContextOptionsBuilder<DashboardChartsDbContext>().UseNpgsql(s,x=>x.MigrationsHistoryTable("__ef_migrations_history",DashboardChartsDbContext.Schema)).Options);}}
